module RefModule(
  input clk,
  input reset,
  input enable,
  input [11:0] duration,
  output reg pulse
);reg [11:0] obf_count;

  always @(posedge clk or posedge reset) begin
    if (reset) begin
      obf_count <= 0;
      pulse <= 0;
    end else if (enable) begin
      if (obf_count < duration) begin
        obf_count <= obf_count + 1;
        pulse <= 1;
      end else begin
        obf_count <= 0;
        pulse <= 0;
      end
    end else begin
      obf_count <= 0;
      pulse <= 0;
    end
  end

endmodule
